chart.options:
chart: {
  type: 'area',
  height: 350,
  animations: {
    enabled: false
  },
  zoom: {
    enabled: false
  },
},
dataLabels: {
  enabled: false
},
stroke: {
  curve: 'straight'
},
fill: {
  type: 'gradient',
  gradient: {
    opacityFrom: 0.5,
    opacityTo: 0.1
  }
},
markers: {
  size: 5,
  hover: {
    size: 9
  }
},
title: {
  text: 'Sensor Uptime',
},
subtitle: {
  text: 'Dropped readings (null values) leave gaps in the area'
},
tooltip: {
  intersect: true,
  shared: false
},
xaxis: {
  type: 'datetime',
},
yaxis: {
  title: {
    text: 'Throughput (Mbps)'
  }
}
